FROM users u
LEFT JOIN orders o ON u.id = o.user_id;

question:
What is the result of the following SQL query?

colors table: id(1,2,3,4), color('red','blue','red','blue')

SELECT DISTINCT color FROM colors;

What is the result of the following SQL query?

scores table: id(1,2,3,4), value(10, 20, 30, 40)

SELECT AVG(value) FROM scores;

What is the result of the following SQL query?

employees table: id(1,2,3,4), dept('A','A','B','B'), salary(100,200,150,300)

SELECT dept, salary, RANK() OVER (PARTITION BY dept ORDER BY salary DESC) as rnk FROM employees;

code:
SELECT dept, salary,
  RANK() OVER (
    PARTITION BY dept
    ORDER BY salary DESC
  ) as rnk
FROM employees;

question:
How many rows does the following SQL query return?

A table: id(1,2) / B table: id(1,2,3)

SELECT * FROM A CROSS JOIN B;

What is the result of the following SQL query?

employees table: id(1,2,3), name('A','B','C'), manager_id(NULL,1,1)

SELECT e.name AS employee, m.name AS manager FROM employees e LEFT JOIN employees m ON e.manager_id = m.id;

code:
SELECT name FROM employees e
WHERE salary > (
  SELECT AVG(salary)
  FROM employees
  WHERE dept = e.dept
);

question:
What is the result of the following SQL query?

items table: id(1,2,3), name('A','B','C'), category('X','Y','X')

SELECT category, COUNT(*) AS cnt FROM items GROUP BY category ORDER BY cnt DESC;

What is the result of the following SQL query?

products table: id(1,2,3), price(50, 150, 300)

SELECT id, CASE WHEN price < 100 THEN 'low' WHEN price < 200 THEN 'mid' ELSE 'high' END AS tier FROM products;

What is the result of the following SQL query?

orders table: id(1,2,3,4), status('done','pending','done','cancel')

SELECT COUNT(*) FROM orders WHERE status IN ('done', 'cancel');

code:
SELECT COUNT(*)
FROM orders
WHERE status IN ('done', 'cancel');

